#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
    int res=0;char ch=getchar();bool flag=0;
    while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
    return flag ? -res : res ;
}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
const int N=2e5+10;
struct Graph
{
    int head[N],des[N],nxt[N],cnt;
    inline void ins(int x,int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
}a;
priority_queue<int> h[N];int stk[N],top,val[N];
inline int Merge(int x,int y)
{
    if(h[x].size()>h[y].size())Swap(x,y);
    while(!h[x].empty())
    {
        int u1=h[x].top(),u2=h[y].top();
        h[x].pop();h[y].pop();stk[++top]=max(u1,u2);
    }
    while(top)h[y].push(stk[top--]);return y;
}
inline int dfs(int u=1)
{
    int tmp=u;grep(a,u,i)
    {
        int v=a.des[i],idx=dfs(v);
        tmp=Merge(tmp,idx);
    }
    h[tmp].push(val[u]);return tmp;
}
int main()
{
    int n=read();rep(1,n,i)val[i]=read();
    rep(2,n,i)a.ins(read(),i);int p=dfs(1);
    // rep(1,n,i)grep(a,i,j)printf("%d %d\n",i,a.des[j]);
    long long ans=0;
    while(!h[p].empty())ans+=h[p].top(),h[p].pop();
    printf("%lld\n",ans);return 0;
}
